function handleResponse(e,r){if(r?.customResponseParser)return e;var t=getResponseType(e.headers.get("content-type"));return parseResponse(e,{...r,type:t})}function handleError(e){return"Failed to fetch"===e.message?Promise.reject({error:e}):Promise.reject(e)}function getResponseType(e){if(!e)return null;if(e.includes("json"))return"json";if(e.includes("text"))return"text";if(e.includes("blob"))return"blob";if(e.includes("x-www-form-urlencoded"))return"formData";throw new Error(`zlFetch does not support content-type ${e} yet`)}async function parseResponse(r,t){if("formData"===t.type){let e=await r.text();if("undefined"!=typeof URLSearchParams){var s=new URLSearchParams(e);e=Object.fromEntries(s)}else{const n=require("querystring");e=n.parse(e)}return createOutput({response:r,body:e,options:t})}s=await r[t.type]();return createOutput({response:r,body:s,options:t})}function createOutput({response:t,body:s,options:e}){s={body:s,headers:getHeaders(t),response:t,status:t.status,statusText:t.statusText};if(!e.returnError)return t.ok?Promise.resolve(s):Promise.reject(s);if(e.returnError){let e,r;return r=t.ok?(e=s,null):(e=null,s),Promise.resolve({response:e,error:r})}}function getHeaders(e){return(e.headers.entries?getBrowserFetchHeaders:getNodeFetchHeaders)(e)}function getBrowserFetchHeaders(e){const r={};for(var[t,s]of e.headers.entries())r[t]=s;return r}function getNodeFetchHeaders(e){const r={},t=e.headers._headers;for(const s in t)r[s]=t[s].join("");return r}export{handleResponse,handleError};